const LIVRO_LINGUAS = [
  { titulo: 'Línguas', subtitulo: true, texto: 'Utilizadas por todos os seres, seja por palavras, sons, atos, desenhos ou escritas.' },
  { titulo: 'Comum', texto: `Língua padrão entre diferentes povos. Simples, direta e amplamente compreendida.<br><em>"Estamos em paz, viajante."</em>` },
  { titulo: 'Élfico', texto: `Língua melodiosa, sons suaves e estruturas poéticas. Usada para encantamentos e canções antigas.<br><em>"Lai thal'evan siren, meldor." (A luz da floresta te guia, amigo.)</em>` },
  { titulo: 'Anão', texto: `Dialeto gutural e robusto. Carregado de tradição e honra.<br><em>"Barok dunhazan, brennok zhul." (O ferro é eterno, o sangue é firme.)</em>` },
  { titulo: 'Orc', texto: `Linguagem áspera e direta, com raízes tribais. Fala com força e instinto.<br><em>"Kraag mor! Tak ven!" (Morte vem! Ataque agora!)</em>` },
  { titulo: 'Gigante', texto: `Voz imponente e cadenciada, ecoa como trovão.<br><em>"Dorn vekgar runa thal." (As montanhas lembram teu nome.)</em>` },
  { titulo: 'Dracônico', texto: `Antiga, poderosa e cheia de ressonância mágica. Cada palavra carrega peso arcano.<br><em>"Thurirl ekess shilta svabol." (O destino decide tudo.)</em>` },
  { titulo: 'Primordial', texto: `Sons elementais puros — sussurros do fogo, rugidos da terra, murmúrios do vento.<br><em>"Sa-ka-vor." (Desça, torrente.)</em>` },
  { titulo: 'Celestial', texto: `Harmônica e límpida, como se falada por harpas vivas. Inspira calma e reverência.<br><em>"Seraphiel illuminaris, pax." (Luz celestial, traga a paz.)</em>` },
  { titulo: 'Terrarians', texto: `Língua nativa dos filhos da terra, palavras graves e longas sílabas.<br><em>"Gorhan thurmak ven'tar." (A pedra vigia nossos passos.)</em>` },
  { titulo: 'Goblinoide', texto: `Grunhidos e frases curtas. Prática, agressiva, adaptada a emboscadas.<br><em>"Snikt rak! Gral nok!" (Morde rápido! Foge depois!)</em>` },
  { titulo: 'Farfico', texto: `Idioma féerico, instável, repleto de jogos de palavras e ritmo irregular.<br><em>"Tiralim dael, oh dael tiralim!" (A dança gira, e a gira dança!)</em>` },
  { titulo: 'Abissal', texto: `Palavras corrosivas, dissonantes, quase dolorosas de escutar. Ligada ao caos e à escuridão.<br><em>"Z'garoth mal venekhul." (Tudo ruirá em tormento.)</em>` },
  { titulo: 'Aéreo', texto: `Leve, com muitos sons assoprados e sílabas curtas. Difícil de entender sem ouvidos apurados.<br><em>"Shae el'ka ni vuhl." (Levanta e some com o vento.)</em>` },
  { titulo: 'Gnomo', texto: `Agitada, rápida e cheia de contrações. Adiciona termos técnicos até para saudações.<br><em>"Zim'vak! Pronto pra pipocar?" (Olá! Preparado pra explodir algo?)</em>` },
  { titulo: 'Gnoll', texto: `Ruge, rosna e berra em vez de estrutura convencional. Carrega intenção mais que precisão.<br><em>"Grrrr-kragh! Ha-ha-RAH!" (Sangue quente! Festa de caça!)</em>` },
  { titulo: 'Aquan', texto: `Sons líquidos, palavras que fluem como correnteza. Falam mais com vibrações que sílabas.<br><em>"Lu'vatha en marinth." (Sinta as marés dentro de ti.)</em>` },
  { titulo: 'Halflings', texto: `Descontraída, com gírias e termos simples. Muito gestual, reforçada por expressões corporais.<br><em>"Ei! Tá bom demais da conta, uai!"</em>` },
  { titulo: 'Terran', texto: `Rústica, profunda, como o eco sob cavernas. Transmite força e antiguidade.<br><em>"Durnak groth venor." (A rocha nunca esquece.)</em>` },
  { titulo: 'Subterrâneo', texto: `Mistura de línguas esquecidas, adaptada ao silêncio e ecos das profundezas. Quase sempre sussurrada.<br><em>"Sik'ver ta'rhan." (Olhos nos cantos, ouvidos na pedra.)</em>` },
];

